classdef PaperStudySelectedSparseEvaluator
    %PAPERSTUDYSELECTEDSPARSEEVALUATOR Frozen-setting P2 sparse evidence.
    %
    % Each primary and diagnostic method is copied only from its v2-selected
    % scale. All methods still share the rendered points, labels, masks, and
    % exact camera geometry. Traceability: algo/main.tex Secs. 6--10 and the
    % unified experimental program; paper_study_tuning_v2 policy.

    properties (SetAccess = private)
        Manifest (1, 1) struct
    end

    methods
        function obj = PaperStudySelectedSparseEvaluator(manifest)
            arguments
                manifest (1, 1) struct {mustBeSelectedSparseManifest}
            end
            obj.Manifest = manifest;
        end

        function result = evaluate(obj, rendered)
            arguments
                obj (1, 1) PaperStudySelectedSparseEvaluator
                rendered (1, 1) struct {mustBeSelectedSparseCase}
            end

            timer = tic;
            methods = string(obj.Manifest.methods.primaryMatching(:));
            setting = obj.primarySettings(methods);
            pair = [setting.DerivativeSigma, setting.IntegrationSigma];
            [scale, ~, group] = unique(pair, "rows", "stable");
            ng = size(scale, 1);
            evaluator = PaperStudySparseEvaluator(obj.Manifest);
            costs = struct;
            selected = struct;
            valid = struct;
            support = struct;
            metrics = struct;
            rows = cell(numel(methods), 1);
            scaleEvaluation = cell(ng, 1);
            groupMethods = cell(ng, 1);
            groupSeconds = zeros(ng, 1);
            for g = 1:ng
                use = find(group == g);
                groupMethods{g} = methods(use).';
                q = evaluator.evaluate(rendered, ...
                    DerivativeSigma=scale(g, 1), ...
                    IntegrationSigma=scale(g, 2));
                scaleEvaluation{g} = q;
                groupSeconds(g) = q.EvaluationSeconds.Total;
                for k = use.'
                    name = char(methods(k));
                    costs.(name) = q.PrimaryCurves.Costs.(name);
                    selected.(name) = ...
                        q.PrimaryCurves.SelectedHeight.(name);
                    valid.(name) = q.PrimaryCurves.Valid.(name);
                    support.(name) = ...
                        q.PrimaryCurves.SupportFraction.(name);
                    metrics.(name) = q.Metrics.(name);
                    rows{k} = ...
                        PaperStudySelectedSparseEvaluator.primaryRow( ...
                        q.Summary(q.Summary.Method == methods(k), :), ...
                        q.Metrics.(name));
                end
            end

            [wlSetting, logSetting] = obj.diagnosticSettings;
            wl = evaluator.evaluateDiagnostics(rendered, ...
                DerivativeSigma=wlSetting.DerivativeSigma, ...
                IntegrationSigma=wlSetting.IntegrationSigma, ...
                MaximumConditionNumber= ...
                wlSetting.AuxiliarySettingValue, ...
                IncludeWidelyLinear=true, IncludeComplexLog=false);
            logq = evaluator.evaluateDiagnostics(rendered, ...
                DerivativeSigma=logSetting.DerivativeSigma, ...
                IntegrationSigma=logSetting.IntegrationSigma, ...
                GradientEnergyPercentile= ...
                logSetting.AuxiliarySettingValue, ...
                IncludeWidelyLinear=false, IncludeComplexLog=true);
            wlRow = PaperStudySelectedSparseEvaluator.diagnosticRow( ...
                rendered, wl, "WidelyLinearResidual", "FullFit", ...
                wl.WidelyLinearResidual.Metrics.FullFit);
            logRow = PaperStudySelectedSparseEvaluator.diagnosticRow( ...
                rendered, logq, "ComplexLogResidual", "ResidualCost", ...
                logq.ComplexLogResidual.Metrics.ResidualCost);
            summary = [vertcat(rows{:}); wlRow; logRow];
            scaleGroups = table((1:ng).', scale(:, 1), scale(:, 2), ...
                groupMethods, groupSeconds, VariableNames=["CostGroup", ...
                "DerivativeSigma", "IntegrationSigma", "Methods", ...
                "EvaluationSeconds"]);
            curves = struct("ReferencePixel", ...
                scaleEvaluation{1}.ReferencePixel, ...
                "Height", rendered.HeightLabelsMetres, ...
                "Costs", costs, "SelectedHeight", selected, ...
                "Valid", valid, "SupportFraction", support, ...
                "Regularization", "none", ...
                "Definition", "one frozen setting per primary method");
            direction = PaperStudySelectedSparseEvaluator. ...
                directionDiagnostics(rendered, metrics, wl, logq);
            result = struct( ...
                "Identifier", rendered.Identifier, ...
                "MethodNames", methods.', ...
                "PrimaryCurves", curves, ...
                "Metrics", metrics, ...
                "Summary", summary, ...
                "ScaleGroups", scaleGroups, ...
                "ScaleEvaluations", {scaleEvaluation}, ...
                "WidelyLinearResidual", wl.WidelyLinearResidual, ...
                "ComplexLogResidual", logq.ComplexLogResidual, ...
                "DirectionDiagnostics", direction, ...
                "Regularization", "none", ...
                "PixelConvention", rendered.PixelConvention, ...
                "WorldFrame", rendered.WorldFrame, ...
                "ElevationDatum", rendered.ElevationDatum, ...
                "TotalSeconds", toc(timer));
        end
    end

    methods (Access = private)
        function setting = primarySettings(obj, methods)
            s = obj.Manifest.frozenPolicy.primarySettings;
            d = zeros(numel(methods), 1);
            q = zeros(numel(methods), 1);
            for k = 1:numel(methods)
                j = find(string({s.method}) == methods(k));
                d(k) = s(j).derivativeSigma;
                q(k) = s(j).integrationSigma;
            end
            setting = table(methods, d, q, VariableNames=[ ...
                "Method", "DerivativeSigma", "IntegrationSigma"]);
        end

        function [wl, logq] = diagnosticSettings(obj)
            s = obj.Manifest.frozenPolicy.diagnosticSettings;
            wl = PaperStudySelectedSparseEvaluator.settingRow( ...
                PaperStudySelectedSparseEvaluator.findSetting( ...
                s, "WidelyLinearResidual"));
            logq = PaperStudySelectedSparseEvaluator.settingRow( ...
                PaperStudySelectedSparseEvaluator.findSetting( ...
                s, "ComplexLogResidual"));
        end
    end

    methods (Static, Access = private)
        function out = findSetting(s, method)
            % Heterogeneous JSON objects decode as cells in MATLAB.
            if iscell(s)
                names = string(cellfun(@(x) x.method, s, ...
                    UniformOutput=false));
                out = s{find(names == method, 1)};
            else
                names = string({s.method});
                out = s(find(names == method, 1));
            end
        end

        function out = settingRow(s)
            if isfield(s, "maximumConditionNumber")
                value = s.maximumConditionNumber;
            else
                value = s.gradientEnergyPercentile;
            end
            out = struct("DerivativeSigma", s.derivativeSigma, ...
                "IntegrationSigma", s.integrationSigma, ...
                "AuxiliarySettingValue", value);
        end

        function row = primaryRow(source, metric)
            row = table(source.Method, "RawSparse", ...
                source.SampleCount, source.EndpointCoverage, ...
                source.EndpointEpeRmsePixels, ...
                source.EndpointEpeP50Pixels, ...
                source.EndpointEpeP90Pixels, ...
                source.EndpointEpeP95Pixels, source.HeightMaeMetres, ...
                source.HeightRmseMetres, ...
                source.MeanTruthCostPercentile, ...
                mean(metric.CostAtTruthLabel, "omitnan"), ...
                source.UniqueTruthBestFraction, ...
                VariableNames=["Method", "Stage", "SampleCount", ...
                "Coverage", "EndpointEpeRmsePixels", ...
                "EndpointEpeP50Pixels", "EndpointEpeP90Pixels", ...
                "EndpointEpeP95Pixels", "HeightMaeMetres", ...
                "HeightRmseMetres", "MeanTruthCostPercentile", ...
                "MeanCostAtTruthLabel", "UniqueTruthBestFraction"]);
        end

        function row = diagnosticRow(rendered, q, method, curveName, m)
            p = q.ReferencePixel;
            use = rendered.TruthValid;
            truth = rendered.TruthCorrespondenceXY(use, :);
            h = m.SelectedHeightMetres;
            geom = HeightSweepGeometry(rendered.ReferenceCamera, ...
                rendered.MatchingMovingCamera);
            [w, projected, inside] = geom.warp(p, h);
            valid = projected & inside & all(isfinite(truth), 2);
            e = vecnorm(w - truth, 2, 2);
            e(~valid) = NaN;
            dh = m.SelectedHeightErrorMetres;
            dh(~valid) = NaN;
            row = table(method, "RawSparse", numel(h), mean(valid), ...
                PaperStudySelectedSparseEvaluator.rmsFinite(e), ...
                PaperStudySelectedSparseEvaluator.percentile(e, 50), ...
                PaperStudySelectedSparseEvaluator.percentile(e, 90), ...
                PaperStudySelectedSparseEvaluator.percentile(e, 95), ...
                mean(abs(dh), "omitnan"), ...
                PaperStudySelectedSparseEvaluator.rmsFinite(dh), ...
                mean(m.TruthCostPercentile, "omitnan"), ...
                mean(m.CostAtTruthLabel, "omitnan"), ...
                mean(m.IsUniqueTruthBest, "omitnan"), ...
                VariableNames=["Method", "Stage", "SampleCount", ...
                "Coverage", "EndpointEpeRmsePixels", ...
                "EndpointEpeP50Pixels", "EndpointEpeP90Pixels", ...
                "EndpointEpeP95Pixels", "HeightMaeMetres", ...
                "HeightRmseMetres", "MeanTruthCostPercentile", ...
                "MeanCostAtTruthLabel", "UniqueTruthBestFraction"]);
            row.Properties.Description = curveName;
        end

        function out = directionDiagnostics(rendered, metrics, wl, logq)
            t0 = metrics.T0.CostAtTruthLabel;
            t3 = metrics.T3.CostAtTruthLabel;
            w = wl.WidelyLinearResidual.TruthLabel;
            fit = w.FitValid & isfinite(w.Mu);
            c = logq.ComplexLogResidual.Curve;
            m = logq.ComplexLogResidual.Metrics.ResidualCost;
            n = numel(m.TruthLabelMetres);
            [~, k] = min(abs(c.Height - m.TruthLabelMetres), [], 2);
            ind = sub2ind([n, numel(c.Height)], (1:n).', k);
            rotation = c.RotationRadians(ind);
            rotation2 = c.Spin2RotationRadians(ind);
            gain = c.LogGain(ind);
            v = isfinite(rotation) & isfinite(rotation2) & isfinite(gain);
            out = struct( ...
                "HighDeformation", ...
                rendered.Factors.ObliquityDegrees >= 55, ...
                "T0MeanTruthCost", mean(t0, "omitnan"), ...
                "T3MeanTruthCost", mean(t3, "omitnan"), ...
                "T3TruthCostRelativeReduction", ...
                1 - mean(t3, "omitnan") ./ mean(t0, "omitnan"), ...
                "WidelyLinearFitValidFraction", mean(w.FitValid), ...
                "WidelyLinearPhysicalValidFraction", ...
                mean(w.PhysicalValid), ...
                "WidelyLinearMeanAbsMu", mean(abs(w.Mu(fit)), "omitnan"), ...
                "ComplexLogTruthValidFraction", mean(v), ...
                "ComplexLogRotationBiasDegrees", abs(rad2deg( ...
                angle(mean(exp(1i .* rotation(v)), "omitnan")))), ...
                "ComplexLogSpin2RotationBiasDegrees", abs(rad2deg( ...
                angle(mean(exp(2i .* rotation2(v)), "omitnan")) ./ 2)), ...
                "ComplexLogLogGainBias", abs(mean(gain(v), "omitnan")), ...
                "Radiometry", string(rendered.Factors.Radiometry), ...
                "Texture", string(rendered.Factors.Texture), ...
                "Definition", ...
                "nearest true-height label; high deformation is obliquity >=55 degrees");
        end

        function y = rmsFinite(x)
            x = x(isfinite(x));
            if isempty(x)
                y = NaN;
            else
                y = sqrt(mean(x .^ 2));
            end
        end

        function y = percentile(x, q)
            x = sort(x(isfinite(x)));
            if isempty(x)
                y = NaN;
                return
            end
            u = 1 + (numel(x) - 1) .* q ./ 100;
            a = floor(u);
            b = ceil(u);
            y = x(a) + (u - a) .* (x(b) - x(a));
        end
    end
end

function mustBeSelectedSparseManifest(s)
if ~all(isfield(s, ["methods", "frozenPolicy"])) ...
        || ~all(isfield(s.frozenPolicy, ...
        ["primarySettings", "diagnosticSettings"]))
    error("PaperStudySelectedSparseEvaluator:InvalidManifest", ...
        "A frozen primary and diagnostic policy is required.");
end
end

function mustBeSelectedSparseCase(s)
required = ["Identifier", "Factors", "TruthValid", ...
    "TruthCorrespondenceXY", "HeightLabelsMetres", ...
    "ReferenceCamera", "MatchingMovingCamera", "PixelConvention", ...
    "WorldFrame", "ElevationDatum"];
if ~all(isfield(s, required)) || ~any(s.TruthValid)
    error("PaperStudySelectedSparseEvaluator:InvalidRenderedCase", ...
        "A rendered P2 case with valid sampled truth is required.");
end
end
